// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function worked_http_server_ts_browser_cors_csrf_cookies_2(originAllowed: boolean, safeMethod: boolean, csrfMatches: boolean, sameSite: boolean): { share: boolean; mutate: boolean; reason: string } {
  const share = originAllowed;
  if (safeMethod) return { share, mutate: false, reason: "safe-method" };
  const mutate = csrfMatches && sameSite;
  return { share, mutate, reason: mutate ? "csrf-defended" : "csrf-denied" };
}

